// Java 25 exam prep - Parallel streams
// Learn: reduce a range across threads with a parallel stream.
long total = IntStream.rangeClosed(1, 1_000)
    .parallel()
    .filter(n -> n % 2 == 0)
    .mapToLong(n -> (long) n)
    .sum(); // associative reduction stays correct in parallel
System.out.println(total);
